import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { setActivePinia, createPinia } from 'pinia'
import { useThemeStore } from './theme'

// jsdom does not implement matchMedia — provide a controllable stub.
function mockMatchMedia(prefersDark: boolean) {
  Object.defineProperty(window, 'matchMedia', {
    writable: true,
    value: vi.fn((query: string) => ({
      matches: query === '(prefers-color-scheme: dark)' ? prefersDark : false,
      media: query,
      onchange: null,
      addListener: vi.fn(),
      removeListener: vi.fn(),
      addEventListener: vi.fn(),
      removeEventListener: vi.fn(),
      dispatchEvent: vi.fn(),
    })),
  })
}

beforeEach(() => {
  setActivePinia(createPinia())
  localStorage.clear()
  document.documentElement.classList.remove('dark')
  mockMatchMedia(false)
})

afterEach(() => {
  vi.restoreAllMocks()
})

// ── initialization ────────────────────────────────────────────────────────────

describe('useThemeStore - initialization', () => {
  it('defaults to light theme when system prefers light and no localStorage', () => {
    mockMatchMedia(false)
    const store = useThemeStore()
    expect(store.theme).toBe('light')
    expect(document.documentElement.classList.contains('dark')).toBe(false)
  })

  it('defaults to dark theme when system prefers dark and no localStorage', () => {
    mockMatchMedia(true)
    const store = useThemeStore()
    expect(store.theme).toBe('dark')
    expect(document.documentElement.classList.contains('dark')).toBe(true)
  })

  it('uses localStorage dark value over a light system preference', () => {
    localStorage.setItem('theme', 'dark')
    mockMatchMedia(false)
    const store = useThemeStore()
    expect(store.theme).toBe('dark')
    expect(document.documentElement.classList.contains('dark')).toBe(true)
  })

  it('uses localStorage light value over a dark system preference', () => {
    localStorage.setItem('theme', 'light')
    mockMatchMedia(true)
    const store = useThemeStore()
    expect(store.theme).toBe('light')
    expect(document.documentElement.classList.contains('dark')).toBe(false)
  })
})

// ── toggle ────────────────────────────────────────────────────────────────────

describe('useThemeStore - toggle', () => {
  it('switches from light to dark', () => {
    const store = useThemeStore()
    expect(store.theme).toBe('light')
    store.toggle()
    expect(store.theme).toBe('dark')
    expect(document.documentElement.classList.contains('dark')).toBe(true)
  })

  it('switches from dark to light', () => {
    mockMatchMedia(true)
    const store = useThemeStore()
    expect(store.theme).toBe('dark')
    store.toggle()
    expect(store.theme).toBe('light')
    expect(document.documentElement.classList.contains('dark')).toBe(false)
  })

  it('persists the toggled theme to localStorage', () => {
    const store = useThemeStore()
    store.toggle()
    expect(localStorage.getItem('theme')).toBe('dark')
    store.toggle()
    expect(localStorage.getItem('theme')).toBe('light')
  })
})

